+fn load_all_skills(ctx: &AppContext) -> Result<Vec<SkillRecord>> {
+    let mut all = Vec::new();
+    let mut offset = 0;
+    let limit = 1000;
+
+    loop {
+        let batch = ctx.db.list_skills(limit, offset)?;
+        let batch_len = batch.len();
+        if batch_len == 0 {
+            break;
+        }
+        all.extend(batch);
+        offset += batch_len;
+        if batch_len < limit {
+            break;
+        }
+    }
+
+    Ok(all)
+}
